mapper.select:
SELECT M.NO, M.MEMBER_ID, M.NAME, M.GENDER, M.PHONE, M.ROLE, M.IS_DELETED, M.REGDATE,
( SELECT COUNT(*) FROM BOARD B WHERE B.MEMBER_NO = M.NO AND B.IS_DELETED = 'N' ) AS BOARD_COUNT,
( SELECT COUNT(*) FROM BOARD_COMMENT C WHERE C.MEMBER_NO = M.NO AND C.IS_DELETED = 'N' ) AS COMMENT_COUNT,
( SELECT COUNT(*) FROM BOARD_LIKE L WHERE L.MEMBER_NO = M.NO ) AS LIKE_COUNT
FROM MEMBER M WHERE 1 = 1
AND M.ROLE = #{searchRole}
AND M.IS_DELETED = #{searchDeleted}
AND M.MEMBER_ID = #{keyword}
AND M.NAME LIKE '%' || #{keyword} || '%'
ORDER BY M.NO DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

